var e=[{id:`L2_1`,type:`dialog`,speaker:`BISHOP_REPLACER_NULL_NULL`,text:{KOREA:`.......`,JPN:`……`,ENG:`.......`,TWN:`……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`BISHOP_REPLACER_NULL_NULL`,text:{KOREA:`정신이 들어?`,JPN:`気が付いたか？`,ENG:`Are you awake?`,TWN:`妳醒了？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`.......`,JPN:`……`,ENG:`.......`,TWN:`……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`여긴......?`,JPN:`ここは……？`,ENG:`Where am I?`,TWN:`這裡是？`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`BISHOP_REPLACER_NULL_NULL`,text:{KOREA:`임시 보급기지.`,JPN:`臨時補給基地だ。`,ENG:`A temporary supply station.`,TWN:`臨時補給基地。`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`BISHOP_REPLACER_NULL_NULL`,text:{KOREA:`지금은 버려진 침식지대 일부를 개조한......`,JPN:`今は、捨てられた侵食地帯の一部を改造した……`,ENG:`I set it up in an abandoned Corrupted Area.`,TWN:`是將一部分廢棄侵蝕地區改造後……`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`BISHOP_REPLACER_NULL_NULL`,text:{KOREA:`사령부에서도 모르는 오직 나만의 공간이지.`,JPN:`司令部にも知られていない私だけの空間。`,ENG:`It’s my personal haven. Not even command knows about this place.`,TWN:`連司令部也不知道的，只屬於我的空間。`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`BISHOP_REPLACER_NULL_NULL`,text:{KOREA:`만드느라 꽤 힘들었어.`,JPN:`作るのにかなり苦労したんだ。`,ENG:`Building it was no cakewalk.`,TWN:`為了建造這裡，我費了很大的功夫呢。`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`BISHOP_REPLACER_NULL_NULL`,text:{KOREA:`의외라는 표정인데?`,JPN:`意外そうな表情だね？`,ENG:`Why do you look so surprised?`,TWN:`妳的表情看起來挺驚訝的？`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`......어째서 이런 곳에?`,JPN:`……どうして、こんなところに？`,ENG:`Why... would you bring me here?`,TWN:`……為什麼我會在這種地方？`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`실험실로 보내지 않는 건가?`,JPN:`実験室に送るんじゃなかったの？`,ENG:`You're not going to send me to a lab?`,TWN:`妳不是應該送我去實驗室嗎？`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`BISHOP_REPLACER_NULL_NULL`,text:{KOREA:`내가? 어째서 그래야 하지?`,JPN:`私が？　どうしてそんなことをしなきゃならないんだ？`,ENG:`Me? Why should I?`,TWN:`我？為什麼我要這麼做？`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`뭐? 그게 무슨 소리야?`,JPN:`えっ？　それはどういう意味？`,ENG:`What? What do you mean?`,TWN:`什麼？這是怎麼回事？`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`너도 리플레이서 조직의 일원이잖아.`,JPN:`あなたもリプレイサー組織の一員じゃない。`,ENG:`You're a member of the Replacer.`,TWN:`妳不也是克隆集團的一員嗎？`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`그게 아니라면 대체 왜 우릴 잡으려고 한 거지?`,JPN:`それが目的じゃないなら、どうして私たちを捕まえようとしたの？`,ENG:`Why else would you try to capture us?`,TWN:`如果不是的話，那妳到底為什麼要來抓我們？`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`BISHOP_REPLACER_NULL_NULL`,text:{KOREA:`......착각을 하고 있군.`,JPN:`……なにか勘違いをしているな。`,ENG:`You're mistaken.`,TWN:`……妳誤會了呢。`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`BISHOP_REPLACER_NULL_NULL`,text:{KOREA:`내가 너흴 추적한 건 리플레이서와는 관계없어.`,JPN:`私がお前らを追いかけたのはリプレイサーとは関係のない話だ。`,ENG:`Me chasing you has nothing to do with the Syndicate.`,TWN:`我追捕你們的事和克隆集團無關，`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`BISHOP_REPLACER_NULL_NULL`,text:{KOREA:`그것보다는 좀 더...... 개인적인 이유야.`,JPN:`それよりもっと……個人的な理由だよ。`,ENG:`I had a more... personal reason.`,TWN:`是比這個更要……私人的理由。`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`......개인적인 이유?`,JPN:`……個人的な理由？`,ENG:`Personal reason?`,TWN:`私人的理由？`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`그게 뭔데?`,JPN:`何それ？`,ENG:`What would that be?`,TWN:`那是什麼意思？`},stage:{bg:`MAINSTREAM_340010`,slots:{L:null,C:null,R:null}}}];export{e as default};